import json

with open('baseline-packages-fresh.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: project_basename -> framework -> package -> version
def build_map(data):
    m = {}
    for p in data['projects']:
        name = p['path'].split('/')[-1]
        m[name] = {}
        for fw in p['frameworks']:
            m[name][fw['framework']] = {}
            for pkg in fw['topLevelPackages']:
                m[name][fw['framework']][pkg['id']] = pkg['resolvedVersion']
    return m

b = build_map(baseline)
a = build_map(after)

changes = []
unchanged = []
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    for fw in sorted(set(list(b.get(proj,{}).keys()) + list(a.get(proj,{}).keys()))):
        bp = b.get(proj,{}).get(fw,{})
        ap = a.get(proj,{}).get(fw,{})
        for pkg in sorted(set(list(bp.keys()) + list(ap.keys()))):
            bv = bp.get(pkg, 'N/A')
            av = ap.get(pkg, 'N/A')
            if bv != av:
                changes.append((proj, fw, pkg, bv, av))
            else:
                unchanged.append((proj, fw, pkg, av))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'{c[0]} ({c[1]}): {c[2]} {c[3]} -> {c[4]}')
else:
    print('None')

print(f'\n=== UNCHANGED: {len(unchanged)} packages ===')"

